                    // leak client-side paths to the server (the server uses
                    // this filename verbatim when writing to disk, and any
                    // leading directory components would either escape `dir`
                    // (absolute paths) or reference nonexistent subdirs).
                    parts.append(.inline(Self.partHeaderForFile(boundary: boundary, isFirst: parts.isEmpty, name: key, filename: fileURL.lastPathComponent, mime: mime)))
