                    let mime = contentTypeForFormPart(fileURL) ?? mimeType(for: fileURL)
                    parts.append(.inline(Self.partHeaderForFile(boundary: boundary, isFirst: parts.isEmpty, name: key, filename: fileURL.lastPathComponent, mime: mime)))
                    parts.append(.file(fileURL))
                case let string as String:
